/* ═══════════════════════════════════════════════════════
   UGIP WEBSITE — nav.css
   🎨 ROOT COLOR THEME — all pages copy :root from here
   Color Theme: Slate Blue + Warm Terracotta
   Calm, academic, soothing — not loud
   ═══════════════════════════════════════════════════════ */

:root {
  /* ── Primary Brand Colors ── */
  --primary:        #3b5a8a;   /* Slate Blue */
  --primary-2:      #324e7a;   /* Deeper Slate */
  --primary-d:      #243659;   /* Darkest Slate */
  --primary-l:      #e8eef6;   /* Light Blue tint */
  --primary-xl:     #f3f6fb;   /* Lightest Blue tint */

  /* ── Accent Colors ── */
  --gold:           #c0714f;   /* Warm Terracotta */
  --gold-d:         #a85e3f;   /* Deeper Terracotta */
  --gold-l:         #fdf0eb;   /* Light Terracotta tint */

  /* ── Semantic Colors ── */
  --success:        #2e7d52;
  --warning:        #b45309;
  --error:          #c0392b;
  --info:           #2563a8;

  /* ── Text Colors ── */
  --text:           #1a2333;   /* Near-black blue-tinted */
  --text-s:         #3d4e66;   /* Subtle blue-grey */
  --text-m:         #7a8ca3;   /* Muted */
  --text-inv:       #ffffff;   /* Inverted/white */

  /* ── Surface Colors ── */
  --sur:            #ffffff;
  --sur-2:          #f7f9fc;   /* Very faint blue-white */
  --sur-3:          #edf1f7;

  /* ── Border Colors ── */
  --bdr:            #d0daeb;
  --bdr-s:          #e8eef6;

  /* ── Radius ── */
  --r-xs:           3px;
  --r-sm:           7px;
  --r-md:           11px;
  --r-lg:           16px;
  --r-xl:           24px;

  /* ── Shadows ── */
  --sh-xs:          0 1px 3px rgba(0,0,0,.06);
  --sh-sm:          0 2px 8px rgba(0,0,0,.08);
  --sh-md:          0 6px 24px rgba(0,0,0,.10);
  --sh-lg:          0 16px 48px rgba(0,0,0,.13);
  --sh-b:           0 8px 24px rgba(59,90,138,.28);

  /* ── Transitions ── */
  --t:              .2s;
  --ease:           cubic-bezier(.4,0,.2,1);

  /* ── Layout ── */
  --max-w:          1440px;
  --nav-h:          64px;
  --topbar-h:       44px;
  --header-h:       108px; /* topbar + navbar = 44 + 64 */
}

/* ─────────────────────────────────
   GLOBAL UTILITY RESETS
───────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }

.ico {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 1em; height: 1em;
  flex-shrink: 0;
  vertical-align: middle;
  line-height: 1;
}
.ico svg { width: 100%; height: 100%; display: block; }

.wrap {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 0 24px;
}

/* ─────────────────────────────────
   SITE HEADER SHELL
───────────────────────────────── */
.site-header {
  position: fixed;
  inset: 0 0 auto;
  z-index: 9000;
  background: var(--sur);
  transition: box-shadow var(--t) var(--ease), transform var(--t) var(--ease);
}
.site-header.scrolled { box-shadow: var(--sh-md); }
@media (min-width: 992px) {
  .site-header.hide { transform: translateY(calc(-1 * var(--topbar-h))); }
}

/* ─────────────────────────────────
   TOP BAR
───────────────────────────────── */
.top-bar {
  height: var(--topbar-h);
  background: linear-gradient(90deg, var(--primary-d) 0%, var(--primary-2) 100%);
  position: relative;
  overflow: hidden;
}
.top-bar::after {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(
    45deg, transparent, transparent 20px,
    rgba(255,255,255,.015) 20px, rgba(255,255,255,.015) 40px
  );
}
@media (max-width: 991px) { .top-bar { display: none; } }

.top-bar-inner {
  position: relative;
  z-index: 1;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.tb-left, .tb-right { display: flex; align-items: center; }

.tb-a {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  color: rgba(255,255,255,.65);
  text-decoration: none;
  font-size: .72rem;
  font-weight: 500;
  letter-spacing: .01em;
  padding: 0 11px;
  height: var(--topbar-h);
  white-space: nowrap;
  transition: background var(--t), color var(--t);
}
.tb-a:hover { background: rgba(255,255,255,.09); color: #fff; }
.tb-a .ico { font-size: .88em; opacity: .85; }

.tb-sep {
  width: 1px;
  height: 16px;
  background: rgba(255,255,255,.15);
  flex-shrink: 0;
}

.tb-admin {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(192,113,79,.14);
  border: 1px solid rgba(192,113,79,.35);
  color: var(--gold) !important;
  border-radius: 20px;
  padding: 5px 14px;
  height: auto;
  margin: 0 8px;
  font-size: .72rem;
  font-weight: 700;
  letter-spacing: .02em;
  text-decoration: none;
  transition: background var(--t), border-color var(--t);
}
.tb-admin:hover {
  background: rgba(192,113,79,.24) !important;
  border-color: var(--gold) !important;
}

.tb-socials { display: flex; align-items: center; }
.tb-soc {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: var(--topbar-h);
  color: rgba(255,255,255,.48);
  text-decoration: none;
  transition: background var(--t), color var(--t);
}
.tb-soc .ico { font-size: 14px; }
.tb-soc:hover { background: rgba(255,255,255,.1); color: #fff; }

.tb-apply {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: var(--gold);
  color: #fff !important;
  border-radius: 20px;
  padding: 6px 16px;
  margin-left: 8px;
  font-size: .72rem;
  font-weight: 700;
  letter-spacing: .03em;
  text-transform: uppercase;
  text-decoration: none;
  box-shadow: 0 2px 8px rgba(192,113,79,.35);
  transition: background var(--t), transform var(--t), box-shadow var(--t);
  height: auto;
}
.tb-apply:hover {
  background: var(--gold-d) !important;
  transform: translateY(-1px);
  box-shadow: 0 8px 20px rgba(192,113,79,.38);
}

/* ─────────────────────────────────
   MAIN NAVBAR
───────────────────────────────── */
.navbar {
  height: var(--nav-h);
  border-top: 1px solid var(--bdr-s);
  display: flex;
  align-items: center;
}
.nav-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  gap: 16px;
}

/* Brand */
.brand { display: flex; align-items: center; gap: 14px; flex-shrink: 0; }
.brand-main {
  display: flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  transition: opacity var(--t);
}
.brand-main:hover { opacity: .85; }
.brand-mark {
  width: 46px; height: 46px;
  border-radius: 10px;
  flex-shrink: 0;
  background: linear-gradient(135deg, var(--primary-d) 0%, var(--primary) 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 8px rgba(59,90,138,.3);
  overflow: hidden;
}
.brand-mark svg { width: 28px; height: 28px; }
.brand-text { line-height: 1.25; }
.brand-name {
  font-family: 'Merriweather', serif;
  font-size: 1.08rem;
  font-weight: 700;
  color: var(--primary-d);
  letter-spacing: -.01em;
  display: block;
}
.brand-tagline {
  font-size: .6rem;
  font-weight: 600;
  color: var(--text-m);
  text-transform: uppercase;
  letter-spacing: .1em;
  display: block;
  margin-top: 1px;
}
.brand-sep {
  width: 1px; height: 34px;
  background: var(--bdr);
  flex-shrink: 0;
}
.affil-badge {
  display: flex;
  align-items: center;
  gap: 8px;
  text-decoration: none;
  opacity: .65;
  transition: opacity var(--t);
}
.affil-badge:hover { opacity: 1; }
.affil-mark {
  width: 38px; height: 38px;
  border-radius: 8px;
  flex-shrink: 0;
  background: white;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1.5px solid rgba(59,90,138,.18);
}
.affil-mark svg { width: 22px; height: 22px; }
.affil-text { line-height: 1.25; }
.affil-name  { font-size: .72rem; font-weight: 700; color: var(--text-s); display: block; }
.affil-sub   { font-size: .58rem; font-weight: 500; color: var(--text-m); text-transform: uppercase; letter-spacing: .07em; }

/* Desktop Nav List */
.nav-list {
  display: flex;
  list-style: none;
  align-items: center;
  gap: 1px;
  margin: 0;
  flex: 1;
  justify-content: flex-end;
}

.nav-link {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 7px 11px;
  font-size: .82rem;
  font-weight: 500;
  color: var(--text-s);
  text-decoration: none;
  border-radius: var(--r-sm);
  white-space: nowrap;
  cursor: pointer;
  transition: background var(--t), color var(--t);
  position: relative;
}
.nav-link .ico { font-size: 15px; color: var(--text-m); transition: color var(--t); }
.nav-link:hover,
.nav-link.active { background: var(--primary-xl); color: var(--primary); }
.nav-link:hover .ico, .nav-link.active .ico { color: var(--primary); }
.caret-ico { font-size: 10px !important; opacity: .6; transition: transform var(--t), opacity var(--t); }
.drop-wrap:hover .caret-ico { transform: rotate(180deg); opacity: 1; }

/* Dropdown */
.drop-wrap { position: relative; }
.dropdown {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  background: var(--sur);
  border: 1px solid var(--bdr);
  border-radius: var(--r-lg);
  box-shadow: var(--sh-lg);
  min-width: 238px;
  list-style: none;
  padding: 6px;
  z-index: 300;
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  transform: translateY(-8px) scale(.97);
  transform-origin: top left;
  transition: opacity var(--t) var(--ease),
              transform var(--t) var(--ease),
              visibility var(--t);
}
.dropdown::before {
  content: '';
  position: absolute;
  top: -5px; left: 18px;
  width: 10px; height: 10px;
  background: var(--sur);
  border-top: 1px solid var(--bdr);
  border-left: 1px solid var(--bdr);
  transform: rotate(45deg);
}
.drop-wrap:hover .dropdown,
.drop-wrap:focus-within .dropdown {
  opacity: 1;
  visibility: visible;
  pointer-events: auto;
  transform: translateY(0) scale(1);
}
.dropdown li { list-style: none; }
.dropdown a {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: var(--r-sm);
  font-size: .82rem;
  font-weight: 500;
  color: var(--text-s);
  text-decoration: none;
  transition: background var(--t), color var(--t), padding-left var(--t);
}
.dropdown a .ico { font-size: 15px; color: var(--primary); opacity: .7; transition: opacity var(--t); flex-shrink: 0; }
.dropdown a:hover { background: var(--primary-xl); color: var(--primary); padding-left: 14px; }
.dropdown a:hover .ico { opacity: 1; }
.drop-hr { height: 1px; background: var(--bdr-s); margin: 4px 0; }

/* Hamburger */
.hamburger {
  display: none;
  width: 42px; height: 42px;
  background: none;
  border: 1.5px solid var(--bdr);
  border-radius: var(--r-sm);
  cursor: pointer;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 5px;
  padding: 0;
  flex-shrink: 0;
  transition: border-color var(--t), background var(--t);
}
.hamburger:hover { background: var(--primary-xl); border-color: var(--primary); }
.hamburger span {
  display: block;
  width: 20px; height: 2px;
  background: var(--text);
  border-radius: 2px;
  transition: transform var(--t), opacity var(--t), width var(--t);
}
.hamburger.open { border-color: var(--primary); background: var(--primary-xl); }
.hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); background: var(--primary); }
.hamburger.open span:nth-child(2) { opacity: 0; width: 0; }
.hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); background: var(--primary); }
@media (max-width: 991px) { .hamburger { display: flex; } }

/* ─────────────────────────────────
   MOBILE DRAWER
───────────────────────────────── */
@media (max-width: 991px) {
  .nav-list {
    position: fixed;
    inset: 0 0 0 auto;
    width: min(360px, 94vw);
    height: 100dvh;
    background: var(--sur);
    flex-direction: column;
    align-items: stretch;
    gap: 0;
    justify-content: flex-start;
    overflow-y: auto;
    overflow-x: hidden;
    transform: translateX(110%);
    transition: transform .3s var(--ease);
    box-shadow: none;
    z-index: 8999;
    padding-bottom: 30px;
  }
  .nav-list.open { transform: translateX(0); box-shadow: var(--sh-lg); }

  .drawer-hd {
    background: linear-gradient(145deg, var(--primary-d) 0%, var(--primary-2) 100%);
    padding: 22px 20px 18px;
    flex-shrink: 0;
    position: sticky;
    top: 0;
    z-index: 10;
  }
  .drawer-brand {
    display: flex;
    align-items: center;
    gap: 10px;
    text-decoration: none;
    margin-bottom: 16px;
  }
  .drawer-mark {
    width: 42px; height: 42px;
    border-radius: 10px;
    flex-shrink: 0;
    background: rgba(255,255,255,.12);
    border: 1px solid rgba(255,255,255,.2);
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .drawer-mark svg { width: 26px; height: 26px; }
  .drawer-brand-text { line-height: 1.2; }
  .drawer-name { font-family: 'Merriweather', serif; font-size: 1rem; color: #fff; display: block; }
  .drawer-sub  { font-size: .6rem; color: rgba(255,255,255,.45); text-transform: uppercase; letter-spacing: .08em; }

  .drawer-btns { display: flex; gap: 8px; margin-bottom: 14px; }
  .d-btn {
    flex: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 7px;
    padding: 10px 12px;
    border-radius: 50px;
    font-size: .78rem;
    font-weight: 700;
    text-decoration: none;
    letter-spacing: .02em;
  }
  .d-btn-gold { background: var(--gold); color: #fff; }
  .d-btn-gold:hover { background: var(--gold-d); color: #fff; }
  .d-btn-ghost {
    background: rgba(255,255,255,.1);
    border: 1px solid rgba(255,255,255,.22);
    color: rgba(255,255,255,.9);
  }
  .d-btn-ghost:hover { background: rgba(255,255,255,.18); }
  .d-btn .ico { font-size: 14px; }

  .drawer-socials { display: flex; gap: 6px; flex-wrap: wrap; }
  .drawer-soc {
    width: 32px; height: 32px;
    border-radius: 8px;
    flex-shrink: 0;
    background: rgba(255,255,255,.08);
    border: 1px solid rgba(255,255,255,.14);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: rgba(255,255,255,.55);
    text-decoration: none;
    transition: background var(--t), color var(--t), border-color var(--t);
  }
  .drawer-soc .ico { font-size: 14px; }
  .drawer-soc:hover { background: var(--primary); color: #fff; border-color: var(--primary); }

  .drawer-quick {
    padding: 16px 16px 12px;
    background: var(--sur-2);
    border-bottom: 1px solid var(--bdr);
  }
  .quick-label {
    font-size: .63rem;
    font-weight: 700;
    letter-spacing: .12em;
    text-transform: uppercase;
    color: var(--text-m);
    margin-bottom: 10px;
  }
  .quick-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 7px; }
  .quick-a {
    display: flex;
    align-items: center;
    gap: 7px;
    padding: 9px 11px;
    background: var(--sur);
    border: 1px solid var(--bdr);
    border-radius: var(--r-sm);
    font-size: .79rem;
    font-weight: 500;
    color: var(--text-s);
    text-decoration: none;
    transition: background var(--t), border-color var(--t), color var(--t);
  }
  .quick-a .ico { font-size: 14px; color: var(--primary); flex-shrink: 0; }
  .quick-a:hover { background: var(--primary-xl); border-color: var(--primary); color: var(--primary); }

  .nav-item { list-style: none; border-bottom: 1px solid var(--bdr-s); }
  .nav-item:last-child { border-bottom: none; }
  .nav-link {
    padding: 13px 20px;
    border-radius: 0;
    width: 100%;
    font-size: .87rem;
    color: var(--text);
    justify-content: flex-start;
    gap: 12px;
  }
  .nav-link .ico { font-size: 17px; color: var(--primary); opacity: .8; }
  .nav-link .ico-label { flex: 1; }
  .nav-link.active { background: var(--primary-xl); color: var(--primary); border-left: 3px solid var(--primary); }
  .nav-link.active .ico { opacity: 1; }
  .caret-ico { transition: transform var(--t); }
  .nav-link.drop-open .caret-ico { transform: rotate(180deg); }

  .dropdown {
    position: static;
    opacity: 1;
    visibility: visible;
    pointer-events: auto;
    transform: none;
    box-shadow: none;
    border: none;
    border-radius: 0;
    background: var(--sur-3);
    padding: 0;
    max-height: 0;
    overflow: hidden;
    transition: max-height .3s var(--ease);
  }
  .dropdown::before { display: none; }
  .dropdown.open { max-height: 700px; padding: 6px 0; }
  .dropdown a {
    padding: 10px 20px 10px 48px;
    border-radius: 0;
    font-size: .84rem;
    color: var(--text-s);
    border-bottom: 1px solid rgba(59,90,138,.07);
    transition: background var(--t), color var(--t), padding-left var(--t);
  }
  .dropdown a:last-child { border-bottom: none; }
  .dropdown a:hover { background: var(--primary-l); color: var(--primary); padding-left: 54px; }
  .dropdown a .ico { font-size: 14px; }

  .m-apply { padding: 18px 20px 4px; }
  .m-apply-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    width: 100%;
    padding: 14px;
    background: var(--gold);
    color: #fff;
    border-radius: 50px;
    font-weight: 700;
    font-size: .9rem;
    text-decoration: none;
    box-shadow: 0 8px 24px rgba(192,113,79,.3);
    transition: background var(--t), transform var(--t);
  }
  .m-apply-btn:hover { background: var(--gold-d); transform: translateY(-1px); }
  .m-apply-btn .ico { font-size: 16px; }

  .desktop-only { display: none !important; }
}

@media (min-width: 992px) {
  .mobile-only { display: none !important; }
  .drawer-hd, .drawer-quick, .m-apply { display: none; }
}

/* ─────────────────────────────────
   BACKDROP
───────────────────────────────── */
.backdrop {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(26,35,51,.5);
  backdrop-filter: blur(3px);
  z-index: 8998;
  opacity: 0;
  transition: opacity .3s;
}
.backdrop.show { display: block; opacity: 1; }

/* ─────────────────────────────────
   RESPONSIVE HELPERS
───────────────────────────────── */
@media (max-width: 480px) {
  .wrap { padding: 0 16px; }
}

/* ─────────────────────────────────
   BODY PADDING — compensate for fixed header
   Desktop: topbar(44) + navbar(64) = 108px
   Mobile:  topbar hidden, only navbar(64) = 64px
───────────────────────────────── */
body {
  padding-top: var(--header-h, 108px);
}
@media (max-width: 991px) {
  body { padding-top: var(--nav-h, 64px); }
}

/* ═══════════════════════════════════════════════════════
   CRITICAL MOBILE FIX — Hamburger Visibility
   ═══════════════════════════════════════════════════════ */
@media (max-width: 991px) {
  /* Ensure header never overflows */
  .site-header { overflow: visible !important; }

  /* Nav bar must not clip hamburger */
  .navbar { overflow: visible !important; padding: 0; }

  /* nav-inner: brand left, hamburger right — no overflow */
  .nav-inner {
    flex-wrap: nowrap !important;
    overflow: visible !important;
    gap: 8px !important;
    padding: 0 16px;
  }

  /* Brand: allow shrink so hamburger always fits */
  .brand {
    flex: 1 1 auto;
    min-width: 0;
    overflow: hidden;
  }

  /* Brand sep + affil: hide on very small screens to save space */
  .brand-sep { display: none !important; }
  .affil-badge { display: none !important; }

  /* Brand text: truncate if needed */
  .brand-name { font-size: .95rem !important; }
  .brand-tagline { font-size: .55rem !important; }

  /* Hamburger: always visible, always right, never shrink */
  .hamburger {
    display: flex !important;
    flex-shrink: 0 !important;
    min-width: 42px !important;
    width: 42px !important;
    height: 42px !important;
    margin-left: auto;
    z-index: 9001 !important;
    position: relative !important;
  }

  /* Nav list drawer: top = nav height only (topbar hidden on mobile) */
  .nav-list {
    top: var(--nav-h, 64px) !important;
  }
}

@media (max-width: 480px) {
  .nav-inner { padding: 0 12px; gap: 6px !important; }
  .brand-mark { width: 36px !important; height: 36px !important; }
  .brand-name { font-size: .88rem !important; }
}

/* ═══════════════════════════════════════════════════════
   UGIP — Color Theme: Slate Blue + Warm Terracotta
   ═══════════════════════════════════════════════════════ */
:root {
  --primary:        #3b5a8a;
  --primary-2:      #324e7a;
  --primary-d:      #243659;
  --primary-l:      #e8eef6;
  --primary-xl:     #f3f6fb;
  --gold:           #c0714f;
  --gold-d:         #a85e3f;
  --gold-l:         #fdf0eb;
  --success:        #2e7d52;
  --warning:        #b45309;
  --error:          #c0392b;
  --info:           #2563a8;
  --text:           #1a2333;
  --text-s:         #3d4e66;
  --text-m:         #7a8ca3;
  --text-inv:       #ffffff;
  --sur:            #ffffff;
  --sur-2:          #f7f9fc;
  --sur-3:          #edf1f7;
  --bdr:            #d0daeb;
  --bdr-s:          #e8eef6;
  --r-xs:           3px;
  --r-sm:           7px;
  --r-md:           11px;
  --r-lg:           16px;
  --r-xl:           24px;
  --sh-xs:          0 1px 3px rgba(0,0,0,.06);
  --sh-sm:          0 2px 8px rgba(0,0,0,.08);
  --sh-md:          0 6px 24px rgba(0,0,0,.10);
  --sh-lg:          0 16px 48px rgba(0,0,0,.13);
  --sh-b:           0 8px 24px rgba(59,90,138,.28);
  --t:              .2s;
  --ease:           cubic-bezier(.4,0,.2,1);
  --max-w:          1440px;
  --nav-h:          64px;
  --topbar-h:       44px;
  --header-h:       108px; /* topbar + navbar */
  /* Legacy vars used in some pages */
  --white:          #ffffff;
  --navy:           #243659;
  --blue:           #3b5a8a;
  --border:         #d0daeb;
  --text2:          #3d4e66;
  --r3:             11px;
  --sh3:            0 6px 24px rgba(0,0,0,.10);
}


/* ── Base Resets (formerly shared.css) ── */
*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; }
body {
  font-family:'DM Sans', sans-serif;
  background:var(--sur-2);
  color:var(--text);
  overflow-x:hidden;
  -webkit-font-smoothing:antialiased;
  padding-top: var(--header-h, 108px);
}
@media(max-width:991px){ body { padding-top: var(--nav-h, 64px); } }

h1,h2,h3,h4,h5,h6 { font-family:'DM Sans', sans-serif; line-height:1.25; }
p { line-height:1.75; color:var(--text-s); }
a { color:var(--primary); text-decoration:none; transition:color var(--t); }
a:hover { color:var(--primary); }
img { max-width:100%; height:auto; display:block; }

.wrap { max-width:1320px; margin:0 auto; padding:0 24px; }
.wrap-sm { max-width:900px; margin:0 auto; padding:0 24px; }
.ico { display:inline-flex; align-items:center; justify-content:center; width:1em; height:1em; flex-shrink:0; vertical-align:middle; line-height:1; }
.ico svg { width:100%; height:100%; display:block; }

.page-hero {
  background: linear-gradient(135deg, var(--primary-d) 0%, var(--primary-2) 40%, var(--primary) 100%);
  padding: 64px 0 56px;
  position:relative; overflow:hidden;
}
.page-hero::before {
  content:''; position:absolute; inset:0; pointer-events:none;
  background: radial-gradient(circle at 70% 50%, rgba(59,90,138,.2) 0%, transparent 60%);
}
.page-hero::after {
  content:''; position:absolute; bottom:-2px; left:0; right:0; height:60px;
  background: var(--sur-2); clip-path: polygon(0 100%, 100% 100%, 100% 0);
}
.hero-breadcrumb {
  display:inline-flex; align-items:center; gap:7px;
  color:rgba(255,255,255,.65); font-size:.78rem; font-weight:500;
  background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.15);
  border-radius:var(--r-lg); padding:6px 14px; margin-bottom:20px;
  transition:background var(--t), color var(--t);
}
.hero-breadcrumb:hover { background:rgba(255,255,255,.18); color:#fff; }
.page-hero h1 {
  font-size:clamp(1.8rem, 4vw, 2.8rem);
  font-weight:800; color:#fff; letter-spacing:-.02em; margin-bottom:12px;
}
.page-hero p {
  font-size:clamp(.9rem, 2vw, 1.1rem);
  color:rgba(255,255,255,.75); max-width:600px; line-height:1.65; margin:0;
}

.sec-title {
  font-size:clamp(1.4rem, 3.5vw, 2rem);
  font-weight:700; color:var(--primary-d); letter-spacing:-.01em;
  padding-bottom:14px; margin-bottom:2rem; position:relative;
}
.sec-title::after {
  content:''; position:absolute; bottom:0; left:0;
  width:52px; height:3px; border-radius:2px;
  background: linear-gradient(90deg, var(--primary), var(--gold));
}
.sec-title.center { text-align:center; }
.sec-title.center::after { left:50%; transform:translateX(-50%); }

.stats-row { display:grid; grid-template-columns:repeat(auto-fit, minmax(160px, 1fr)); gap:20px; margin:40px 0; }
.stat-box { background:var(--sur); border:1px solid var(--bdr); border-radius:var(--r-md); padding:28px 20px; text-align:center; box-shadow:var(--sh-xs); transition:transform var(--t), box-shadow var(--t); }
.stat-box:hover { transform:translateY(-4px); box-shadow:var(--sh-md); }
.stat-num { font-family:'DM Sans', sans-serif; font-size:2.2rem; font-weight:800; color:var(--primary); line-height:1; }
.stat-lbl { font-size:.82rem; font-weight:600; color:var(--text-s); margin-top:6px; text-transform:uppercase; letter-spacing:.05em; }

.card-grid { display:grid; grid-template-columns:repeat(auto-fill, minmax(280px,1fr)); gap:24px; }
.card { background:var(--sur); border:1px solid var(--bdr); border-radius:var(--r-md); overflow:hidden; box-shadow:var(--sh-xs); transition:transform var(--t), box-shadow var(--t); }
.card:hover { transform:translateY(-5px); box-shadow:var(--sh-md); }
.card-body { padding:24px; }
.card-title { font-size:1.05rem; font-weight:700; color:var(--primary-d); margin-bottom:10px; }
.card-text { font-size:.9rem; color:var(--text-s); line-height:1.7; }

.btn-primary { display:inline-flex; align-items:center; gap:8px; background:var(--primary); color:#fff; font-weight:600; font-size:.9rem; padding:12px 24px; border-radius:var(--r-lg); border:none; cursor:pointer; box-shadow:var(--sh-b); transition:background var(--t), transform var(--t), box-shadow var(--t); text-decoration:none; }
.btn-primary:hover { background:var(--primary-2); transform:translateY(-2px); box-shadow:0 8px 28px rgba(59,90,138,.4); color:#fff; }
.btn-outline { display:inline-flex; align-items:center; gap:8px; background:transparent; color:var(--primary); font-weight:600; font-size:.9rem; padding:11px 22px; border-radius:var(--r-lg); border:2px solid var(--primary); cursor:pointer; transition:background var(--t), color var(--t); text-decoration:none; }
.btn-outline:hover { background:var(--primary); color:#fff; }
.btn-sm { padding:8px 18px; font-size:.82rem; }

.table-wrap { overflow-x:auto; border-radius:var(--r-sm); border:1px solid var(--bdr); }
table { width:100%; border-collapse:collapse; background:var(--sur); }
thead tr { background:var(--primary-d); }
thead th { color:#fff; font-family:'DM Sans', sans-serif; font-size:.8rem; font-weight:700; text-transform:uppercase; letter-spacing:.07em; padding:14px 16px; text-align:left; }
tbody td { padding:13px 16px; border-bottom:1px solid var(--bdr); font-size:.88rem; color:var(--text-s); vertical-align:middle; }
tbody tr:last-child td { border-bottom:none; }
tbody tr:hover td { background:var(--primary-xl); }
tbody tr:nth-child(even) { background:var(--sur-3); }
tbody tr:nth-child(even):hover td { background:var(--primary-xl); }

.badge { display:inline-block; padding:4px 12px; border-radius:20px; font-size:.72rem; font-weight:700; letter-spacing:.04em; text-transform:uppercase; }
.badge-blue { background:var(--primary-xl); color:var(--primary); }
.badge-gold { background:var(--gold-l); color:var(--gold-d); }
.badge-green { background:#d1fae5; color:#065f46; }
.badge-red { background:#fee2e2; color:#991b1b; }
.badge-navy { background:var(--primary-d); color:#fff; }

.form-group { margin-bottom:20px; }
.form-label { display:block; font-size:.85rem; font-weight:600; color:var(--text); margin-bottom:8px; }
.form-control { width:100%; padding:11px 14px; border:1.5px solid var(--bdr); border-radius:var(--r-sm); font-family:inherit; font-size:.9rem; color:var(--text); background:var(--sur); transition:border-color var(--t), box-shadow var(--t); outline:none; }
.form-control:focus { border-color:var(--primary); box-shadow:0 0 0 3px rgba(59,90,138,.12); }

.accordion { border:1px solid var(--bdr); border-radius:var(--r-md); overflow:hidden; }
.acc-item { border-bottom:1px solid var(--bdr); }
.acc-item:last-child { border-bottom:none; }
.acc-toggle { width:100%; background:var(--sur); border:none; padding:18px 24px; display:flex; justify-content:space-between; align-items:center; font-family:'DM Sans', sans-serif; font-size:.95rem; font-weight:600; color:var(--primary-d); cursor:pointer; text-align:left; transition:background var(--t), color var(--t); }
.acc-toggle:hover { background:var(--primary-xl); color:var(--primary); }
.acc-toggle.open { background:var(--primary-d); color:#fff; }
.acc-toggle .acc-icon { font-size:1.2rem; transition:transform var(--t); flex-shrink:0; margin-left:12px; }
.acc-toggle.open .acc-icon { transform:rotate(45deg); }
.acc-body { display:none; padding:20px 24px; background:var(--sur-2); border-top:1px solid var(--bdr); }
.acc-body.open { display:block; }

.timeline { position:relative; padding-left:40px; }
.timeline::before { content:''; position:absolute; left:12px; top:0; bottom:0; width:2px; background:var(--bdr); border-radius:2px; }
.tl-item { position:relative; margin-bottom:32px; }
.tl-item::before { content:''; position:absolute; left:-34px; top:6px; width:14px; height:14px; background:var(--primary); border-radius:50%; border:3px solid var(--sur); box-shadow:0 0 0 2px var(--primary); }
.tl-year { font-size:.78rem; font-weight:800; color:var(--primary); text-transform:uppercase; letter-spacing:.1em; margin-bottom:4px; }
.tl-title { font-size:1rem; font-weight:700; color:var(--primary-d); margin-bottom:6px; }
.tl-body { font-size:.88rem; color:var(--text-s); line-height:1.7; }

.vm-grid { display:grid; grid-template-columns:repeat(auto-fit, minmax(300px,1fr)); gap:24px; }
.vm-card { background:var(--sur); border:1px solid var(--bdr); border-radius:var(--r-md); padding:36px 28px; text-align:center; position:relative; overflow:hidden; box-shadow:var(--sh-xs); }
.vm-card::before { content:''; position:absolute; top:0; left:0; right:0; height:4px; background:linear-gradient(90deg, var(--primary), var(--gold)); }
.vm-icon { width:64px; height:64px; border-radius:50%; background:var(--primary-xl); display:flex; align-items:center; justify-content:center; margin:0 auto 18px; font-size:1.8rem; }
.vm-card h3 { font-size:1.2rem; font-weight:700; color:var(--primary-d); margin-bottom:12px; }
.vm-card p { font-size:.9rem; color:var(--text-s); line-height:1.75; }

.info-card { background:var(--sur); border:1px solid var(--bdr); border-radius:var(--r-md); padding:28px; display:flex; gap:20px; align-items:flex-start; box-shadow:var(--sh-xs); transition:transform var(--t), box-shadow var(--t); }
.info-card:hover { transform:translateY(-4px); box-shadow:var(--sh-md); }
.info-icon { width:52px; height:52px; flex-shrink:0; border-radius:12px; background:var(--primary-xl); display:flex; align-items:center; justify-content:center; font-size:1.5rem; color:var(--primary); }
.info-content h4 { font-size:.95rem; font-weight:700; color:var(--primary-d); margin-bottom:6px; }
.info-content p { font-size:.85rem; margin:0; line-height:1.65; }
.info-content a { color:var(--primary); font-weight:600; font-size:.85rem; }

.sec { padding:72px 0; }
.sec-sm { padding:48px 0; }
.sec-alt { background:var(--sur); }
.sec-dark { background:var(--primary-d); }
.sec-dark .sec-title { color:#fff; }
.sec-dark p { color:rgba(255,255,255,.72); }

.filter-bar { display:flex; flex-wrap:wrap; gap:10px; margin-bottom:32px; }
.filter-tag { padding:8px 18px; border-radius:var(--r-lg); border:1.5px solid var(--bdr); background:var(--sur); color:var(--text-s); font-size:.82rem; font-weight:600; cursor:pointer; transition:all var(--t); }
.filter-tag:hover, .filter-tag.active { background:var(--primary); color:#fff; border-color:var(--primary); }

.two-col { display:grid; grid-template-columns:1fr 1fr; gap:40px; align-items:start; }
@media(max-width:768px){ .two-col { grid-template-columns:1fr; } }

.gallery-grid { display:grid; grid-template-columns:repeat(auto-fill, minmax(260px,1fr)); gap:16px; }
.gallery-item { position:relative; border-radius:var(--r-sm); overflow:hidden; aspect-ratio:4/3; cursor:pointer; }
.gallery-item img { width:100%; height:100%; object-fit:cover; transition:transform .4s var(--ease); }
.gallery-item:hover img { transform:scale(1.07); }
.gallery-overlay { position:absolute; inset:0; background:rgba(26,35,51,.52); display:flex; flex-direction:column; justify-content:flex-end; padding:16px; opacity:0; transition:opacity var(--t); }
.gallery-item:hover .gallery-overlay { opacity:1; }
.gallery-caption { color:#fff; font-size:.83rem; font-weight:600; }
.gallery-cat { font-size:.72rem; color:rgba(255,255,255,.7); }

@media(max-width:640px) {
  .page-hero { padding:44px 0 40px; }
  .sec { padding:48px 0; }
  .stats-row { grid-template-columns:repeat(2, 1fr); }
  .card-grid { grid-template-columns:1fr; }
  .wrap { padding: 0 16px; }
  .two-col { grid-template-columns: 1fr; gap:24px; }
  .vm-grid { grid-template-columns: 1fr; }
  .gallery-grid { grid-template-columns: repeat(2, 1fr); }
  .filter-bar { gap:8px; }
  .filter-tag { padding:6px 12px; font-size:.78rem; }
  .page-hero h1 { font-size: 1.6rem; }
}
@media(max-width:400px) {
  .gallery-grid { grid-template-columns: 1fr; }
  .stats-row { grid-template-columns: 1fr; }
}


/* ─── Page-specific styles below ─── */
/* ═══════════════════════════════════════════════════════
   UGIP WEBSITE — footer.css
   Uses CSS vars defined in nav.css
   ═══════════════════════════════════════════════════════ */

/* ─────────────────────────────────
   BACK TO TOP BUTTON
───────────────────────────────── */
#btt {
  position: fixed;
  bottom: 28px;
  right: 28px;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  background: var(--primary);
  color: #fff;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 6px 20px rgba(26,92,58,.4);
  opacity: 0;
  visibility: hidden;
  transform: translateY(16px);
  transition: opacity .25s, visibility .25s, transform .25s, background .2s, box-shadow .2s;
  z-index: 1200;
}
#btt .ico { font-size: 20px; }
#btt.show {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}
#btt:hover {
  background: var(--gold);
  color: var(--primary-d);
  box-shadow: 0 8px 24px rgba(224,123,0,.4);
  transform: translateY(-3px);
}
#btt:active { transform: translateY(0); }

/* Tooltip label on BTT */
#btt::after {
  content: 'Top';
  position: absolute;
  right: calc(100% + 8px);
  top: 50%;
  transform: translateY(-50%);
  background: var(--primary-d);
  color: #fff;
  font-size: .65rem;
  font-weight: 700;
  letter-spacing: .06em;
  text-transform: uppercase;
  padding: 4px 9px;
  border-radius: 20px;
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity .2s;
}
#btt:hover::after { opacity: 1; }

@media (max-width: 480px) {
  #btt { bottom: 20px; right: 16px; width: 42px; height: 42px; }
}

/* ─────────────────────────────────
   SITE FOOTER
───────────────────────────────── */
.site-footer {
  background: #061a0e;
  color: rgba(255,255,255,.72);
  border-top: 3px solid var(--primary);
  position: relative;
  overflow: hidden;
}
.site-footer::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 60% 40% at 5% 95%, rgba(26,92,58,.1) 0%, transparent 70%),
    radial-gradient(ellipse 40% 30% at 95% 10%, rgba(224,123,0,.05) 0%, transparent 70%),
    url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.015'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
}

.footer-body {
  position: relative;
  z-index: 1;
  padding: 64px 0 56px;
}

.f-grid {
  display: grid;
  grid-template-columns: 2fr 1.6fr 1fr 1fr 1fr;
  gap: 52px 40px;
  align-items: start;
}
@media (max-width: 1200px) { .f-grid { grid-template-columns: 1fr 1fr 1fr; gap: 40px 32px; } }
@media (max-width: 700px)  { .f-grid { grid-template-columns: 1fr 1fr; gap: 36px 24px; } }
@media (max-width: 480px)  { .f-grid { grid-template-columns: 1fr; gap: 32px; } }

/* Section Headings */
.f-heading {
  font-size: .68rem;
  font-weight: 700;
  letter-spacing: .14em;
  text-transform: uppercase;
  color: rgba(255,255,255,.32);
  margin-bottom: 18px;
  padding-bottom: 10px;
  border-bottom: 1px solid rgba(255,255,255,.07);
  display: flex;
  align-items: center;
  gap: 8px;
}
.f-heading .ico { font-size: 13px; color: rgba(255,255,255,.22); }

/* Brand Column */
.f-brand-logo {
  display: flex;
  align-items: center;
  gap: 12px;
  text-decoration: none;
  margin-bottom: 18px;
}
.f-logo-mark {
  width: 48px; height: 48px;
  border-radius: 11px;
  flex-shrink: 0;
  background: linear-gradient(135deg, var(--primary-d) 0%, var(--primary) 100%);
  border: 1px solid rgba(255,255,255,.12);
  display: flex;
  align-items: center;
  justify-content: center;
}
.f-logo-mark svg { width: 28px; height: 28px; }
.f-brand-name-wrap { line-height: 1.25; }
.f-brand-name {
  font-family: 'Merriweather', serif;
  font-size: 1.15rem;
  color: #fff;
  font-weight: 700;
  display: block;
}
.f-brand-sub {
  font-size: .6rem;
  text-transform: uppercase;
  letter-spacing: .1em;
  color: rgba(255,255,255,.38);
  margin-top: 2px;
  display: block;
}

.f-about {
  font-size: .85rem;
  line-height: 1.85;
  color: rgba(255,255,255,.48);
  margin-bottom: 22px;
}

.f-affil {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(255,255,255,.05);
  border: 1px solid rgba(255,255,255,.09);
  border-radius: 8px;
  padding: 8px 12px;
  margin-bottom: 20px;
  text-decoration: none;
  transition: background .2s;
}
.f-affil:hover { background: rgba(255,255,255,.1); }
.f-affil-mark {
  width: 28px; height: 28px;
  border-radius: 6px;
  background: white;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.f-affil-mark svg { width: 18px; height: 18px; }
.f-affil-text { line-height: 1.2; }
.f-affil-name { font-size: .78rem; font-weight: 700; color: rgba(255,255,255,.8); display: block; }
.f-affil-sub  { font-size: .6rem; color: rgba(255,255,255,.38); text-transform: uppercase; letter-spacing: .06em; }

.f-socials { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 4px; }
.f-soc {
  width: 36px; height: 36px;
  border-radius: 9px;
  background: rgba(255,255,255,.06);
  border: 1px solid rgba(255,255,255,.1);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: rgba(255,255,255,.5);
  text-decoration: none;
  transition: background .2s, color .2s, border-color .2s, transform .2s;
}
.f-soc .ico { font-size: 15px; }
.f-soc:hover { background: var(--primary); border-color: var(--primary); color: #fff; transform: translateY(-3px); }

/* Contact Column */
.f-contacts { list-style: none; padding: 0; }
.f-ci { display: flex; gap: 12px; margin-bottom: 16px; align-items: flex-start; }
.f-ci:last-child { margin-bottom: 0; }
.f-ci-icon {
  width: 34px; height: 34px;
  border-radius: 9px;
  flex-shrink: 0;
  background: rgba(26,92,58,.18);
  border: 1px solid rgba(26,92,58,.3);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-top: 1px;
}
.f-ci-icon .ico { font-size: 15px; color: #7bcfa0; }
.f-ci-body { line-height: 1.6; }
.f-ci-label {
  font-size: .65rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: .09em;
  color: rgba(255,255,255,.27);
  display: block;
  margin-bottom: 1px;
}
.f-ci-val { font-size: .84rem; color: rgba(255,255,255,.65); }
.f-ci-val a { color: rgba(255,255,255,.65); text-decoration: none; transition: color .2s; }
.f-ci-val a:hover { color: #fff; }

.hours-chip {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  background: rgba(26,92,58,.12);
  border: 1px solid rgba(26,92,58,.3);
  border-radius: 20px;
  padding: 6px 14px;
  margin: 16px 0;
  font-size: .75rem;
  font-weight: 600;
  color: #7bcfa0;
}
.hours-chip .ico { font-size: 13px; }

.f-map {
  border-radius: 11px;
  overflow: hidden;
  border: 1px solid rgba(255,255,255,.08);
  margin-top: 4px;
}
.f-map iframe { display: block; }

/* Links Columns */
.f-links { list-style: none; padding: 0; }
.f-links li { margin-bottom: 9px; }
.f-links a {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: .84rem;
  font-weight: 400;
  color: rgba(255,255,255,.52);
  text-decoration: none;
  transition: color .2s, transform .2s;
}
.f-links a .ico { font-size: 13px; color: rgba(255,255,255,.22); flex-shrink: 0; transition: color .2s; }
.f-links a:hover { color: #fff; transform: translateX(4px); }
.f-links a:hover .ico { color: var(--primary); }

/* Footer Bottom Bar */
.footer-bottom {
  position: relative;
  z-index: 1;
  border-top: 1px solid rgba(255,255,255,.07);
  padding: 20px 0;
}
.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
}
.footer-bottom p { font-size: .78rem; color: rgba(255,255,255,.28); }
.footer-bottom strong { color: rgba(255,255,255,.48); font-weight: 600; }
.footer-bottom a { color: rgba(255,255,255,.35); text-decoration: none; transition: color .2s; }
.footer-bottom a:hover { color: #fff; }

.live-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: .72rem;
  font-weight: 600;
  color: rgba(255,255,255,.4);
}
.live-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
  background: #22c55e;
  box-shadow: 0 0 0 0 rgba(34,197,94,.4);
  animation: ping 1.8s ease-in-out infinite;
}
@keyframes ping {
  0%, 100% { box-shadow: 0 0 0 0 rgba(34,197,94,.4); }
  50%       { box-shadow: 0 0 0 5px rgba(34,197,94,0); }
}

@media (max-width: 640px) {
  .footer-bottom-inner { flex-direction: column; text-align: center; }
}
